            if not full_link.startswith(os.path.normpath(dest)):
                raise tarfile.ExtractError("Unsafe symlink")
        return member

    try:
        with tarfile.open(tar_path, 'r') as tar:
            # Use filter if available (Python 3.12+), otherwise fallback
            try:
                tar.extractall(path=dest_path, filter=lambda m: safe_filter(m, dest_path))
            except TypeError:
                # Fallback for older Python: validate all members first
                for member in tar.getmembers():
                    safe_filter(member, dest_path)
                tar.extractall(path=dest_path)
        return True
    except Exception:
        return False

