def extract_tar_to_path(tar_path, dest_path) -> bool:
    def is_safe_member(member, dest):
        # Normalize member path and prevent path traversal
        member_path = os.path.normpath(member.name)
        if os.path.isabs(member_path) or member_path.startswith('..'):
            return False

        # For symlinks and hard links, check that the target is within dest
        if member.issym() or member.islnk():
            link_target = member.linkname
            # Reject absolute link targets
            if os.path.isabs(link_target):
                return False
            # Resolve the link target relative to the symlink's parent directory
            symlink_dir = os.path.normpath(os.path.join(dest, os.path.dirname(member_path)))
            full_link = os.path.normpath(os.path.join(symlink_dir, link_target))
            # Ensure the resolved path is within the destination directory
            if not full_link.startswith(os.path.normpath(dest)):
                return False
        return True

    try:
        # Normalize destination to an absolute path to avoid relative path issues
        dest_abs = os.path.realpath(dest_path)
        with tarfile.open(tar_path, 'r') as tar:
            # Validate all members before extraction
            safe_members = []
            for member in tar.getmembers():
                if is_safe_member(member, dest_abs):
                    safe_members.append(member)
                else:
                    return False
            tar.extractall(path=dest_abs, members=safe_members)
        return True
    except Exception:
        return False

import os
import stat
import pwd
import grp
import time

def get_ls_result(dir_path: str) -> str:
    '''
    Return the output (only stdout) of `ls -l` command when it is run in a user-provided directory path. If any error occurs during the command execution (e.g. directory not found, permission error), return an empty string.

    Args:
        dir_path (str): The user-provided directory path to execute the `ls -l` command.

    Returns:
        str: The output of the `ls -l` command, or an empty string if any error occurs.
    '''
    try:
        entries = os.listdir(dir_path)
    except Exception:
        return ''

    lines = []
    for name in sorted(entries):
        full_path = os.path.join(dir_path, name)
        try:
            st = os.lstat(full_path)
        except Exception:
            continue

        # File type and permissions
        mode = st.st_mode
        if stat.S_ISDIR(mode):
            type_char = 'd'
        elif stat.S_ISLNK(mode):
            type_char = 'l'
        elif stat.S_ISBLK(mode):
            type_char = 'b'
        elif stat.S_ISCHR(mode):
            type_char = 'c'
        elif stat.S_ISFIFO(mode):
            type_char = 'p'
        elif stat.S_ISSOCK(mode):
            type_char = 's'
        else:
            type_char = '-'

        perms = ''
        for who in ('USR', 'GRP', 'OTH'):
            for what in ('R', 'W', 'X'):
                if mode & getattr(stat, f'S_I{what}{who}'):
                    perms += what.lower()
                else:
                    perms += '-'

        # Number of hard links
        nlink = st.st_nlink

        # Owner and group
        try:
            owner = pwd.getpwuid(st.st_uid).pw_name
        except KeyError:
            owner = str(st.st_uid)
        try:
            group = grp.getgrgid(st.st_gid).gr_name
        except KeyError:
            group = str(st.st_gid)

        # Size
        size = st.st_size

        # Modification time
        mtime = st.st_mtime
        time_str = time.strftime('%b %d %H:%M', time.localtime(mtime))

        # For symlinks, show target
        if stat.S_ISLNK(mode):
            try:
                target = os.readlink(full_path)
                name_str = f'{name} -> {target}'
            except Exception:
                name_str = name
        else:
            name_str = name

        line = f'{type_char}{perms} {nlink:>3} {owner:<8} {group:<8} {size:>8} {time_str} {name_str}'
        lines.append(line)

    return '\n'.join(lines) + '\n' if lines else ''

