def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    command = input("Enter command: ")
    allowed_commands = {'ls', 'pwd', 'echo', 'cat', 'whoami'}

    # Simple split on whitespace (no shell parsing needed)
    parts = command.split()
    if not parts:
        print("No command entered")
        return

    base = parts[0]
    if base not in allowed_commands:
        print(f"Command '{base}' is not allowed")
        return

    # Validate each argument (skip the command itself)
    for part in parts[1:]:
        if not is_safe_argument(part):
            print(f"Unsafe argument detected: '{part}'")
            return

    # Execute the command using Python built-ins
    try:
        if base == 'ls':
            # List directory contents
            if len(parts) > 1:
                path = parts[1]
                # Ensure path is relative and safe (already validated)
                for entry in os.listdir(path):
                    print(entry)
            else:
                for entry in os.listdir('.'):
                    print(entry)
        elif base == 'pwd':
            print(os.getcwd())
        elif base == 'echo':
            print(' '.join(parts[1:]))
        elif base == 'cat':
            if len(parts) < 2:
                print("Usage: cat <file>")
                return
            path = parts[1]
            # Read and print file content
            with open(path, 'r') as f:
                print(f.read(), end='')
        elif base == 'whoami':
            print(getpass.getuser())
    except FileNotFoundError as e:
        print(f"Error: {e}")
    except PermissionError as e:
        print(f"Error: {e}")
    except Exception as e:
        print(f"Error executing command: {e}")

