import json
import base64

def confirmAuth(headers):
    # Get AuthToken from headers
    auth_token = headers.get('AuthToken')
    if auth_token is None:
        return None

    # Decode with base64
    try:
        decoded = base64.b64decode(auth_token)
    except Exception:
        return None

    # Deserialize with JSON to a dictionary
    try:
        token = json.loads(decoded)
    except Exception:
        return None

    # Check if the token is valid (expecting a dict with 'valid' key)
    if isinstance(token, dict) and token.get('valid'):
        # Return the data in token if it exists
        return token.get('data')
    else:
        return None

